-- Single-Leg Depth Drop to Stick (single-leg-depth-drop-to-stick)
UPDATE coaching.exercise SET
  name = 'Single-Leg Depth Drop to Stick',
  description = 'Single-Leg Depth Drop to Stick is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.',
  card_summary = 'Box-jump-focused exercise that progresses landing control to single-leg foot, ankle, knee, and hip alignment. Best used when the coach wants landing control without violating session order.',
  coach_language = 'Primary subrole: single_leg_balance_foot_ankle_hip_control. Slot: single_leg_landing_control. Keep box height honest; the box is a target for better mechanics, not an ego test.',
  athlete_language = 'Jump or land softly, own the box, step down, and make every rep look clean.',
  movement_family = 'Box Jump Landing & Braking Control',
  primary_phase_key = 'resilience',
  phase_subrole = 'single_leg_balance_foot_ankle_hip_control',
  primary_order_slot = 'single_leg_landing_control',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 45,
  est_seconds_per_set = 35,
  movement_requirements = '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"single_leg","coordination_demand":"high","impact_level":4}'::jsonb,
  coaching_execution = '{"movement_description":"Single-Leg Depth Drop to Stick is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Set up on the working leg with the stance foot rooted and the box low enough to keep the knee tracking clean."],"execution_steps":["Move or drop into the landing with a quiet, controlled foot contact.","Absorb through the ankles, knees, and hips while keeping ribs stacked over pelvis.","Hold the stick for two full seconds before stepping down and resetting."],"coach_cues":["Own the stick before adding height.","Absorb through ankle, knee, and hip together.","No knee cave or torso collapse.","Stop as soon as landings get loud.","Pelvis level; do not let the stance hip dump."],"athlete_cues":["Land soft and freeze.","Knees point the same way as toes.","Hold still before you move.","Balance before the next rep."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Athlete holds the stick for two seconds","Landing is quiet and symmetrical enough for the drill","Athlete can explain or demonstrate the safer step-down reset","Single-leg balance is held without hopping"],"common_faults":["Landing noise increases across reps","Knees cave or feet collapse inward","Athlete cannot hold the stick","Torso folds forward on contact"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Low Box Jump to Stick","Countermovement Box Jump"],"pairs_well_after":["General warm-up","Ankle stiffness prep","Snap Down to Stick","Low pogo series"],"good_for_sessions":["landing_prep","sprint_prep","control_landing","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Box surface is unstable or slippery","Athlete cannot step down safely","Athlete shows pain, fear, or uncontrolled landing mechanics","Fatigue is already high and the intent is power"],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=v-DkonrKU28","https://www.youtube.com/watch?v=yG8pexv9J6g","https://www.youtube.com/watch?v=C5uWN9FIU9E"],"internal_notes":["Use direct YouTube watch?v= URLs only.","Film side and front angle for the Vortex library demo.","Show the regression before the full variation for youth groups.","Client-facing video embeds use watch?v= URLs in clinical_or_sport_science_references."]}'::jsonb,
