UPDATE coaching.exercise SET
  name = 'Box Jump Step-Down Reset',
  description = 'Box Jump Step-Down Reset is a technical box-jump skill drill. The athlete moves at a teachable speed, coordinates the takeoff and landing sequence, and resets every rep so the pattern stays crisp. It prepares the athlete for higher-intent box jumps without turning the set into conditioning.',
  card_summary = 'Box-jump-focused exercise that teaches the safest box-jump rhythm: jump up, stick, stand tall, step down, reset before the next rep. Best used when the coach wants technical skill without violating session order.',
  coach_language = 'Primary subrole: balance_coordination_rhythm. Slot: box_jump_mechanics. Keep box height honest; the box is a target for better mechanics, not an ego test.',
