  est_seconds_per_set = 40,
  movement_requirements = '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Box Jump Step-Down Reset is a technical box-jump skill drill. The athlete moves at a teachable speed, coordinates the takeoff and landing sequence, and resets every rep so the pattern stays crisp. It prepares the athlete for higher-intent box jumps without turning the set into conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Load the hips with control and swing the arms in rhythm with the jump pattern.","Jump or move over the box with enough height to clear safely without rushing.","Land, stand tall, step down, and reset before the next rep."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb,
