-- Box Jump with Altitude Landing (box-jump-with-altitude-landing)
UPDATE coaching.exercise SET
  name = 'Box Jump with Altitude Landing',
  description = 'Box Jump with Altitude Landing is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.',
  card_summary = 'Box-jump-focused exercise that pairs an upward jump with a deliberate drop-and-stick to train landing tolerance after box contact. Best used when the coach wants landing control without violating session order.',
  coach_language = 'Primary subrole: landing_braking_control. Slot: landing_braking_control. Keep box height honest; the box is a target for better mechanics, not an ego test.',
  athlete_language = 'Jump or land softly, own the box, step down, and make every rep look clean.',
  movement_family = 'Box Jump Landing & Braking Control',
  primary_phase_key = 'resilience',
  phase_subrole = 'landing_braking_control',
  primary_order_slot = 'landing_braking_control',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 45,
  est_seconds_per_set = 35,
  movement_requirements = '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"high","impact_level":4}'::jsonb,
  coaching_execution = '{"movement_description":"Box Jump with Altitude Landing is a box-jump-family landing-control drill. The athlete uses the box or drop height only as high as they can absorb quietly, holds the landing shape, then resets before the next attempt. The main goal is braking skill, joint alignment, and tissue tolerance rather than chasing height or fatigue.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Move or drop into the landing with a quiet, controlled foot contact.","Absorb through the ankles, knees, and hips while keeping ribs stacked over pelvis.","Hold the stick for two full seconds before stepping down and resetting."],"coach_cues":["Own the stick before adding height.","Absorb through ankle, knee, and hip together.","No knee cave or torso collapse.","Stop as soon as landings get loud."],"athlete_cues":["Land soft and freeze.","Knees point the same way as toes.","Hold still before you move."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Athlete holds the stick for two seconds","Landing is quiet and symmetrical enough for the drill","Athlete can explain or demonstrate the safer step-down reset"],"common_faults":["Landing noise increases across reps","Knees cave or feet collapse inward","Athlete cannot hold the stick","Torso folds forward on contact"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Low Box Jump to Stick","Countermovement Box Jump"],"pairs_well_after":["General warm-up","Ankle stiffness prep","Snap Down to Stick","Low pogo series"],"good_for_sessions":["landing_prep","sprint_prep","control_landing","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Box surface is unstable or slippery","Athlete cannot step down safely","Athlete shows pain, fear, or uncontrolled landing mechanics","Fatigue is already high and the intent is power"],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=ZL54zeg6qjg","https://www.youtube.com/watch?v=v-DkonrKU28","https://www.youtube.com/watch?v=-ZGryFyvnt4"],"internal_notes":["Use direct YouTube watch?v= URLs only.","Film side and front angle for the Vortex library demo.","Show the regression before the full variation for youth groups.","Client-facing video embeds use watch?v= URLs in clinical_or_sport_science_references."]}'::jsonb,
  updated_at = now()
WHERE slug = 'box-jump-with-altitude-landing';

