-- Reset Repetition Box Jump (reset-repetition-box-jump)
UPDATE coaching.exercise SET
  name = 'Reset Repetition Box Jump',
  description = 'Reset Repetition Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.',
  card_summary = 'Box-jump-focused exercise that keeps every rep high-quality by forcing a full step-down and athletic reset between jumps. Best used when the coach wants power expression without violating session order.',
  coach_language = 'Primary subrole: jump_throw_explosive_power. Slot: box_jump_power. Keep box height honest; the box is a target for better mechanics, not an ego test.',
  athlete_language = 'Jump or land softly, own the box, step down, and make every rep look clean.',
  movement_family = 'Box Jump Explosive Power',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'box_jump_power',
  participant_structure = 'individual',
  default_sets = 3,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 45,
