  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=G-bxQY57mKc","https://www.youtube.com/watch?v=fTpI4tgjci0","https://www.youtube.com/watch?v=cLSB_Zn0awM"],"internal_notes":["Use direct YouTube watch?v= URLs only.","Film side and front angle for the Vortex library demo.","Show the regression before the full variation for youth groups.","Client-facing video embeds use watch?v= URLs in clinical_or_sport_science_references."]}'::jsonb,
