-- Low Consecutive Rebound Box Jump (low-consecutive-rebound-box-jump)
UPDATE coaching.exercise SET
  name = 'Low Consecutive Rebound Box Jump',
  description = 'Low Consecutive Rebound Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.',
  card_summary = 'Box-jump-focused exercise that uses a very low box and capped contacts to teach quick rebounding without turning the set into conditioning. Best used when the coach wants power expression without violating session order.',
  coach_language = 'Primary subrole: elastic_stiffness_plyometric_rudiments. Slot: elastic_to_box_power. Keep box height honest; the box is a target for better mechanics, not an ego test.',
  athlete_language = 'Jump or land softly, own the box, step down, and make every rep look clean.',
  movement_family = 'Box Jump Explosive Power',
  primary_phase_key = 'output',
  phase_subrole = 'elastic_stiffness_plyometric_rudiments',
  primary_order_slot = 'elastic_to_box_power',
  participant_structure = 'individual',
  default_sets = 3,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"high","impact_level":4}'::jsonb,
  coaching_execution = '{"movement_description":"Low Consecutive Rebound Box Jump is a high-intent box-jump power exercise. The athlete creates a crisp takeoff, lands softly on the box with full-foot control, stands tall, steps down, and fully resets. The purpose is explosive force expression with low volume and full recovery, not conditioning.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Load quickly but under control, then drive the floor away with full-body intent.","Land on the box with the whole foot, knees tracking over toes, and chest organized.","Stand tall, step down, and rest long enough for the next rep to be just as explosive."],"coach_cues":["Jump up, not forward into the box.","Quiet feet on the box.","Knees track over the middle toes.","Step down; do not rebound off a high box."],"athlete_cues":["Land like a ninja.","Stick the landing before you stand tall.","Step down and reset."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Every landing is quiet and controlled","Athlete steps down safely","No knee valgus, foot collapse, or torso panic","Next rep looks as good as the first rep"],"common_faults":["Box height too high for a clean landing","Knees collapsing inward","Landing on the toes or front edge of the box","Rebounding down from the box instead of stepping down"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box"],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Heavy lower-body strength","Sled push","Medicine-ball throws","Acceleration work"],"pairs_well_after":["General warm-up","Ankle stiffness prep","Snap Down to Stick","Low pogo series"],"good_for_sessions":["landing_prep","sprint_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Box surface is unstable or slippery","Athlete cannot step down safely","Athlete shows pain, fear, or uncontrolled landing mechanics","Fatigue is already high and the intent is power"],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=G-bxQY57mKc","https://www.youtube.com/watch?v=cLSB_Zn0awM","https://www.youtube.com/watch?v=fTpI4tgjci0"],"internal_notes":["Use direct YouTube watch?v= URLs only.","Film side and front angle for the Vortex library demo.","Show the regression before the full variation for youth groups.","Client-facing video embeds use watch?v= URLs in clinical_or_sport_science_references."]}'::jsonb,
