-- Burpee Box Jump-Over (burpee-box-jump-over)
UPDATE coaching.exercise SET
  name = 'Burpee Box Jump-Over',
  description = 'Burpee Box Jump-Over is a conditioning-only box-jump pattern. The athlete combines a floor-to-box transition with repeatable jumping mechanics and must maintain safe posture under fatigue. It belongs late in the session, never before speed, max jumping, or technical skill work.',
  card_summary = 'Box-jump-focused exercise that a conditioning-only box-jump pattern for athletes who can maintain safe mechanics under fatigue. Best used when the coach wants conditioning repeatability without violating session order.',
  coach_language = 'Primary subrole: conditioning_circuit. Slot: conditioning_circuit. Keep box height honest; the box is a target for better mechanics, not an ego test.',
  athlete_language = 'Jump or land softly, own the box, step down, and make every rep look clean.',
  movement_family = 'Box Jump Conditioning Repeatability',
  primary_phase_key = 'sustained_capacity',
  phase_subrole = 'conditioning_circuit',
  primary_order_slot = 'conditioning_circuit',
  participant_structure = 'individual',
