  default_reps = 3,
  default_work_seconds = 40,
  default_rest_seconds = 80,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["ankle_plantarflexion","knee_extension","hip_extension","hip_knee_ankle_flexion_landing"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","intrinsic_foot"],"primary_motor_control_demands":["takeoff_timing","landing_alignment","postural_stiffness"],"postural_shape":"athletic_stance_to_stacked_landing","breathing_demand":"brace_and_exhale_on_effort","balance_demand":"dynamic","coordination_demand":"high","impact_level":4}'::jsonb,
  coaching_execution = '{"movement_description":"Burpee Box Jump-Over is a conditioning-only box-jump pattern. The athlete combines a floor-to-box transition with repeatable jumping mechanics and must maintain safe posture under fatigue. It belongs late in the session, never before speed, max jumping, or technical skill work.","setup":["Use a stable, non-slip box at a height the athlete can land on without tucking excessively.","Clear the surrounding area and set the athlete far enough from the box to jump vertically, not dive forward.","Begin in an athletic stance with eyes on the top/front edge of the box."],"execution_steps":["Move from the floor into the box jump-over pattern at a pace you can control.","Land with both feet secure before stepping or hopping down on the opposite side.","Keep breathing and posture consistent; slow down before mechanics degrade."],"coach_cues":["Conditioning intent only; keep it late.","Pace so mechanics stay safe.","No missed box contacts.","Lower the box before grinding reps."],"athlete_cues":["Move smooth, not sloppy.","Both feet secure on the box.","Slow down before your landings get loud."],"breathing_cues":["Brace before takeoff","Exhale naturally after landing or during the reset"],"quality_gate":["Athlete can keep a sustainable pace without missed contacts","Box height remains conservative","Breathing is elevated but movement quality is not collapsing"],"common_faults":["Rushing the box contact","Tripping or clipping the box","Turning the lower back into the driver during burpees","Continuing after jump mechanics degrade"],"stop_signs":["Missed box contact or tripping","Knee, Achilles, back, or hip pain","Landing quality worsens for two reps in a row","Athlete begins jumping down from a high box","Athlete cannot maintain safe breathing or posture under fatigue"],"regressions":[],"progressions":[]}'::jsonb,
