-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for box-jump progressions: landing control, takeoff power, reactive combinations, and safe step-down reset behavior.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('snap-down-to-stick', 'The box reduces landing drop from the upward jump while giving the athlete an external target. Used correctly, Snap Down to Stick lets the coach bias takeoff power, landing control, or coordination while limiting unnecessary eccentric overload.', 'This belongs in Resilience because the adaptation target is braking quality, landing tolerance, and joint control, not maximal power.', 'Resilience block after warm-up, Output, or Capacity when the goal is landing control rather than maximal jump height.', 'Rushing to height or speed before the athlete can stick the landing; this changes a control drill into uncontrolled impact.', 'Scale by box height, approach complexity, landing demand, external load, and total contacts. Progress only when the athlete keeps quiet landings and full reset quality.'),
  ('low-box-step-off-to-stick', 'The box reduces landing drop from the upward jump while giving the athlete an external target. Used correctly, Low Box Step-Off to Stick lets the coach bias takeoff power, landing control, or coordination while limiting unnecessary eccentric overload.', 'This belongs in Resilience because the adaptation target is braking quality, landing tolerance, and joint control, not maximal power.', 'Resilience block after warm-up, Output, or Capacity when the goal is landing control rather than maximal jump height.', 'Rushing to height or speed before the athlete can stick the landing; this changes a control drill into uncontrolled impact.', 'Scale by box height, approach complexity, landing demand, external load, and total contacts. Progress only when the athlete keeps quiet landings and full reset quality.'),
  ('depth-drop-to-athletic-stick', 'The box reduces landing drop from the upward jump while giving the athlete an external target. Used correctly, Depth Drop to Athletic Stick lets the coach bias takeoff power, landing control, or coordination while limiting unnecessary eccentric overload.', 'This belongs in Resilience because the adaptation target is braking quality, landing tolerance, and joint control, not maximal power.', 'Resilience block after warm-up, Output, or Capacity when the goal is landing control rather than maximal jump height.', 'Rushing to height or speed before the athlete can stick the landing; this changes a control drill into uncontrolled impact.', 'Scale by box height, approach complexity, landing demand, external load, and total contacts. Progress only when the athlete keeps quiet landings and full reset quality.'),
  ('single-leg-depth-drop-to-stick', 'The box reduces landing drop from the upward jump while giving the athlete an external target. Used correctly, Single-Leg Depth Drop to Stick lets the coach bias takeoff power, landing control, or coordination while limiting unnecessary eccentric overload.', 'This belongs in Resilience because the adaptation target is braking quality, landing tolerance, and joint control, not maximal power.', 'Resilience block after warm-up, Output, or Capacity when the goal is landing control rather than maximal jump height.', 'Rushing to height or speed before the athlete can stick the landing; this changes a control drill into uncontrolled impact.', 'Scale by box height, approach complexity, landing demand, external load, and total contacts. Progress only when the athlete keeps quiet landings and full reset quality.'),
  ('box-jump-step-down-reset', 'The box reduces landing drop from the upward jump while giving the athlete an external target. Used correctly, Box Jump Step-Down Reset lets the coach bias takeoff power, landing control, or coordination while limiting unnecessary eccentric overload.', 'This belongs in Movement Intelligence because the athlete is learning timing and spatial control before fatigue or high-intent work.', 'Movement Intelligence block before high-intent jumping; use as crisp teaching reps, not fatigue work.', 'Letting the drill become a race or finisher; the learning target disappears when reps get rushed.', 'Scale by box height, approach complexity, landing demand, external load, and total contacts. Progress only when the athlete keeps quiet landings and full reset quality.'),
  ('low-box-jump-to-stick', 'The box reduces landing drop from the upward jump while giving the athlete an external target. Used correctly, Low Box Jump to Stick lets the coach bias takeoff power, landing control, or coordination while limiting unnecessary eccentric overload.', 'This belongs in Output because high-speed force expression is freshness-sensitive and should happen before fatigue-producing strength or conditioning.', 'Early Output block after warm-up and before heavy strength; give full recovery and stop while jumps are fast.', 'Using box jumps for high-rep fatigue or chasing a box height that forces a deep knee tuck; that turns an Output drill into conditioning and hides poor takeoff quality.', 'Scale by box height, approach complexity, landing demand, external load, and total contacts. Progress only when the athlete keeps quiet landings and full reset quality.'),
