-- Box-jump cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'box_jump_readiness',
  NULL,
  'Box jump programming without ego height or conditioning drift',
  'Box jump work requires honest box height, quiet landings, safe step-down resets, fresh high-intent Output, landing-resilience prep, and conditioning-only variants kept separate from power work.',
  'Box-jump-focused cards span landing and braking sticks, step-down rhythm, bilateral and unilateral box power, reactive combinations, loaded variants, and conditioning-only box jump options.',
  'The box is a coaching target for takeoff, landing, and reset quality — not an ego test. Poor height selection, rushed step-downs, or fatigued box jumps raise injury risk and train noisy contacts.',
  'Fresh box jumps are power. Fatigued box jumps are conditioning. Box height is never more important than clean takeoff, quiet landing, and safe step-down reset.',
  'Do not chase box height before the athlete owns the stick; do not jump down from high boxes; do not convert fresh Output box jumps into a finisher circuit once landing quality drops.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
